SELECT COUNT(1) FROM ( SELECT A.SMS_HISTORY_ID AS SMS_HISTORY_ID, A.REQUEST_ID AS REQUEST_ID, A.SENT_AT AS SENT_AT, A.RECEIVER_NO AS RECEIVER_NO, A.SENDER_NO AS SENDER_NO, A.SEND_TYPE AS SEND_TYPE, A.SEND_STATUS AS SEND_STATUS, A.RESULT_CD AS RESULT_CD, A.RESULT_MSG AS RESULT_MSG FROM SMS.SMS_HISTORY A WHERE 1=1
AND A.SEND_TYPE = #{sendType}
AND A.SEND_STATUS = #{sendStatus}
AND a.sent_at >= TO_TIMESTAMP(#{sentAt} || '000000', 'YYYYMMDDHH24MISS') AND a.sent_at < TO_TIMESTAMP(#{sentAt} || '000000', 'YYYYMMDDHH24MISS') + INTERVAL '1' DAY
AND A.RECEIVER_NO LIKE '%' || #{receiverNo} || '%'
) A

SELECT A.* FROM ( SELECT A.SMS_HISTORY_ID AS SMS_HISTORY_ID, A.REQUEST_ID AS REQUEST_ID, A.SENT_AT AS SENT_AT, A.RECEIVER_NO AS RECEIVER_NO, A.SENDER_NO AS SENDER_NO, A.SEND_TYPE AS SEND_TYPE, A.SEND_STATUS AS SEND_STATUS, A.RESULT_CD AS RESULT_CD, A.RESULT_MSG AS RESULT_MSG FROM SMS.SMS_HISTORY A WHERE 1=1
AND A.SEND_TYPE = #{sendType}
AND A.SEND_STATUS = #{sendStatus}
AND a.sent_at >= TO_TIMESTAMP(#{sentAt} || '000000', 'YYYYMMDDHH24MISS') AND a.sent_at < TO_TIMESTAMP(#{sentAt} || '000000', 'YYYYMMDDHH24MISS') + INTERVAL '1' DAY
AND A.RECEIVER_NO LIKE '%' || #{receiverNo} || '%'
) A
ORDER BY A.RESULT_MSG OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

mapper.update:
UPDATE SMS.SMS_HISTORY
   SET SENT_AT = #{sentAt,jdbcType=TIMESTAMP},
       RECEIVER_NO = #{receiverNo,jdbcType=VARCHAR},
       SENDER_NO = #{senderNo,jdbcType=VARCHAR},
       SEND_TYPE = #{sendType,jdbcType=VARCHAR},
       SEND_STATUS = #{sendStatus,jdbcType=VARCHAR},
       RESULT_CD = #{resultCd,jdbcType=VARCHAR},
       RESULT_MSG = #{resultMsg,jdbcType=VARCHAR}
 WHERE SMS_HISTORY_ID = #{smsHistoryId,jdbcType=NUMERIC}
   AND REQUEST_ID = #{requestId,jdbcType=VARCHAR}
